sys_script.script:
(function executeRule(current, previous) {
    // 1. Check duplicate registration
    var dup = new GlideRecord('x_2097092_linq_registration');
    dup.addQuery('student', current.getValue('student'));
    dup.addQuery('event', current.getValue('event'));
    dup.addQuery('status', '!=', 'cancelled');
    dup.query();
    if (dup.hasNext()) {
        gs.addErrorMessage('You are already registered for this event.');
        current.setAbortAction(true);
        return;
    }

    // 2. Check event status is live
    var event = new GlideRecord('x_2097092_linq_event');
    if (event.get(current.getValue('event'))) {
        if (event.getValue('status') !== 'live') {
            gs.addErrorMessage('This event is not currently accepting registrations.');
            current.setAbortAction(true);
            return;
        }

        // 3. Check inter_college scope and student college status
        if (event.getValue('scope') === 'inter_college') {
            var student = new GlideRecord('sys_user');
            if (student.get(current.getValue('student'))) {
                var collegeId = student.getValue('u_college');
                if (collegeId) {
                    var college = new GlideRecord('x_2097092_linq_college');
                    if (college.get(collegeId)) {
                        if (college.getValue('status') !== 'verified') {
                            gs.addErrorMessage('Your college must be verified to register for inter-college events.');
                            current.setAbortAction(true);
                            return;
                        }
                    }
                }
            }
        }

        // 4. Check capacity
        var ga = new GlideAggregate('x_2097092_linq_registration');
        ga.addQuery('event', current.getValue('event'));
        ga.addQuery('status', '!=', 'cancelled');
        ga.addAggregate('COUNT');
        ga.query();
        var count = 0;
        if (ga.next()) {
            count = parseInt(ga.getAggregate('COUNT'), 10);
        }
        var capacity = parseInt(event.getValue('capacity'), 10);
        if (count >= capacity) {
            gs.addErrorMessage('This event has reached its maximum capacity.');
            current.setAbortAction(true);
            return;
        }
    }
})(current, previous);
